DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGlateximage.pl",
  "PCCmacros.pl",
  "contextForm.pl",
  "contextInequalitySetBuilder.pl",
  "parserGraphTool.pl",
  "Pd.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$var = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context()->variables->are($var => 'Real');
$c = non_zero_random(-6,6);
$a = -1*random(2,20);
$b = $a*$c;
$left = Formula("$a $var")->reduce;
$right = Formula("$b")->reduce;
$sign = list_random('\lt', '\gt', '\leq', '\geq');
%interval = (
  '\lt'  => "($c, inf)",
  '\gt'  => "(-inf, $c)",
  '\leq' => "[$c, inf)",
  '\geq' => "(-inf, $c]"
);
Context("Interval");
$interval = Interval($interval{$sign});
InequalitySetBuilder::UseVerticalSuchThat();
Context("InequalitySetBuilder-Only");
Context()->variables->are($var => 'Real');
%perlsign = (
  '\lt'  => ">",
  '\gt'  => "<",
  '\leq' => ">=",
  '\geq' => "<="
);
$perlsign = $perlsign{$sign};
$setbuilder = Compute("{ $var | $var $perlsign $c}");
$gt = GraphTool("{interval, $interval}")->with(
  availableTools => ['IntervalTool', 'IncludeExcludePointTool'],
  numberLine => 1,
  xAxisLabel => "$var",
  bBox => [ -8, 8 ],
  ticksDistanceX => 1,
  minorTicksX => 0,
  useBracketEnds => 1,
  showInStatic => 0,
  showCoordinateHints => 0,
);
%oppsign = (
  '\lt'  => '\gt',
  '\gt'  => '\lt',
  '\leq' => '\geq',
  '\geq' => '\leq'
);
$oppsign = $oppsign{$sign};
%words = (
  '\lt'  => "less than",
  '\gt'  => "greater than",
  '\leq' => "less than or equal to",
  '\geq' => "greater than or equal to"
);
$words = $words{$oppsign};
if ($oppsign eq '\lt' || $oppsign eq '\gt') {
  $sol[0] = "does not allow";
  $sol[1] = "parenthesis";
  $sol[2] = "infiniteopeninterval";
} else {
  $sol[0] = "allows";
  $sol[1] = "bracket";
  $sol[2] = "infiniteclosedinterval";
}
if ($oppsign eq '\lt' || $oppsign eq '\leq') {
  $sol[3] = -12;
} else {
  $sol[3] = 12;
}

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
$image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \begin{axis}[numberline, xlabel={\($var\)}]
    \addplot[$sol[2]] coordinates {($sol[3],0) ($c,0)};
  \end{axis}
\end{tikzpicture}

END_LATEX_IMAGE

############################################################
# Body
############################################################

BEGIN_PGML
Solve the inequality.

[`[$left][$sign][$right]`]

[_]{$gt}{1}

[@KeyboardInstructions('In interval notation.')@]**

[_]{$interval}{12}

[@KeyboardInstructions('In set-builder notation. (If needed, type [|inf|]* or [|infinity|]* for [`\infty\text{,}`] [|>=|]* for [`\geq\text{,}`] and [|<=|]* for [`\leq\text{.}`])')@]**

[_]{$setbuilder}{12}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
The opposite action to multiplication is division. When we divide by a negative number, the inequality sign must change direction.

[```\newcommand{\highlight}[1]{\mathchoice{\colorbox{lightsapphire}{$\displaystyle #1$}}{\colorbox{lightsapphire}{$\textstyle #1$}}{\colorbox{lightsapphire}{$\scriptstyle #1$}}{\colorbox{lightsapphire}{$\scriptscriptstyle #1$}}}\newcommand{\divideunder}[2]{\frac{#1}{{\highlight{{#2}}}}}
\begin{gathered}
[$left][$sign][$right]\\
\divideunder{[$left]}{[$a]}\highlight{[$oppsign]}\divideunder{[$right]}{[$a]}\\
[$var] [$oppsign] [$c]
\end{gathered}
```]

So in set-builder notation, the solution set is [`[$setbuilder]\text{.}`]

We can graph this by shading all numbers [$words] [`[$c]\text{.}`] Since the sign in the inequality [$sol[0]] for [`[$var]`] to equal [`[$c]\text{,}`] we use a [$sol[1]] at [`[$c]\text{.}`]

>> [@image(insertGraph($image_1), width=>600)@]*  <<

We read the graph from left to right to tell us the interval notation for the solution set: [`[$interval]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
